#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int mcm(vector<int>& p) {
        int n = p.size() - 1;
        vector<vector<int>> dp(n, vector<int>(n));
        for (int length = 2; length <= n; length++) {
            for (int i = 0; i < n - length + 1; i++) {
                int j = i + length - 1;
                dp[i][j] = INT_MAX;
                for (int k = i; k < j; k++) {
                    dp[i][j] = min(dp[i][j], dp[i][k] + dp[k + 1][j] + p[i] * p[k + 1] * p[j + 1]);
                }
            }
        }
        return dp[0][n - 1];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> p(n + 1);
    for (int i = 0; i < n + 1; i++) cin >> p[i];
    Solution sol;
    int ans = sol.mcm(p);
    cout << ans << "\n";
    return 0;
}
